type WidgetInterface interface {
	Create(ctx context.Context, widget *Widget, opts metav1.CreateOptions) (*Widget, error)
	Get(ctx context.Context, name string, opts metav1.GetOptions) (*Widget, error)
	List(ctx context.Context, opts metav1.ListOptions) (*WidgetList, error)
	Delete(ctx context.Context, name string, opts metav1.DeleteOptions) error
}

// WidgetClient implements WidgetInterface
type WidgetClient struct {
	restClient rest.Interface
	namespace  string
}

// NewWidgetClient creates a new Widget client for a given namespace
func NewWidgetClient(c rest.Interface, namespace string) *WidgetClient {
	return &WidgetClient{
		restClient: c,
		namespace:  namespace,
	}
}

// Create creates a new Widget resource
func (c *WidgetClient) Create(ctx context.Context, widget *Widget, opts metav1.CreateOptions) (*Widget, error) {
	result := &Widget{}
	err := c.restClient.Post().
		Namespace(c.namespace).
		Resource("widgets").
		VersionedParams(&opts, scheme.ParameterCodec).
		Body(widget).
		Do(ctx).
		Into(result)
	return result, err
}

// Get retrieves a Widget resource by name
func (c *WidgetClient) Get(ctx context.Context, name string, opts metav1.GetOptions) (*Widget, error) {
	result := &Widget{}
	err := c.restClient.Get().
		Namespace(c.namespace).
		Resource("widgets").
		Name(name).
		VersionedParams(&opts, scheme.ParameterCodec).
		Do(ctx).
		Into(result)
	return result, err
}

// List retrieves a list of Widget resources
func (c *WidgetClient) List(ctx context.Context, opts metav1.ListOptions) (*WidgetList, error) {
	result := &WidgetList{}
	err := c.restClient.Get().
		Namespace(c.namespace).
		Resource("widgets").
		VersionedParams(&opts, scheme.ParameterCodec).
		Do(ctx).
		Into(result)
	return result, err
}

// Delete deletes a Widget resource by name
func (c *WidgetClient) Delete(ctx context.Context, name string, opts metav1.DeleteOptions) error {
	return c.restClient.Delete().
		Namespace(c.namespace).
		Resource("widgets").
		Name(name).
		Body(&opts).
		Do(ctx).
		Error()
}

